import {
  PersonOutlined as PersonOutlinedIcon,
  Search as SearchIcon,
  ShoppingCartOutlined as ShoppingCartOutlinedIcon
} from '@mui/icons-material';
import { Badge, Box, Card, IconButton, InputAdornment, Slide, TextField, Typography, useScrollTrigger, useTheme } from '@mui/material';
import AppBar from '@mui/material/AppBar';
import { navigate } from 'gatsby';
import React, { useState } from 'react';
import useCart from '../../storage/useCart';
import { getQuery, latinCharsKeyboard } from '../../utils/utils';
import useUser from '../../storage/useUser';

type Element = {
  name: string
  isOpen: boolean
}

const mock: Element[] = [{ name: 'UFMG', isOpen: false }, { name: 'CEFET', isOpen: false }, { name: 'PUC', isOpen: false }, { name: 'UNA', isOpen: false }, { name: 'NEWTON PAIVA', isOpen: false }]

export const HeaderCategories = () => {
  const [elements, setElements] = useState<Element[]>(mock)

  const handlePopoverOpen = (element: Element) => {
    setElements((previousE) => previousE.map(e => e.name === element.name
      ? { ...element, isOpen: true }
      : { ...e, isOpen: false }))
  };

  const handlePopoverClose = () => {
    setElements((previousE) => previousE.map(e => ({ ...e, isOpen: false })))
  };

  return <Box onMouseLeave={handlePopoverClose} sx={{ display: 'flex', pl: 28, pr: 28, justifyContent: 'space-around', width: '100%', flexDirection: 'row' }}>
    {elements.map(e => {
      return (
        <Box key={e.name}>
          <Box aria-owns={e.isOpen ? 'mouse-over-popover' : undefined}
            aria-haspopup="true"
            onMouseEnter={() => handlePopoverOpen(e)}
            sx={{ display: 'flex', height: '100%', alignItems: 'center', justifyContent: 'center' }}
          >
            <Box aria-owns={e.isOpen ? 'mouse-over-popover' : undefined}
              sx={{ display: 'flex', height: '100%', alignItems: 'center', justifyContent: 'center', padding: '0px 16px' }}
              borderBottom={e.isOpen ? "4px solid #000" : undefined}
            >
              <Typography color="primary" marginTop={e.isOpen ? "4px" : undefined} fontWeight={e.isOpen ? "bold" : undefined}>
                {e.name}
              </Typography>
            </Box>
          </Box>
          {e.isOpen && (
            <Card
              elevation={8}
              onMouseLeave={handlePopoverClose}
              sx={{ bgcolor: 'white', position: 'absolute', width: '100%', zIndex: 999, left: 0, height: 300, display: 'flex', justifyContent: 'center', alignItems: 'center' }}
            >
              <Typography color="primary">{e.name}</Typography>
            </Card>
          )}
        </Box>
      );
    })}
  </Box>
}

function HideOnScroll(props: any) {
  const { children } = props;
  const trigger = useScrollTrigger();

  return (
    <Slide appear={false} direction="down" in={!trigger}>
      {children}
    </Slide>
  );
}
interface LayoutProps {
  showHeaderCategories?: boolean;
}
const HeaderLarge: React.FC<LayoutProps> = ({ showHeaderCategories }) => {
  const { isLogged } = useUser();
  const userIsLogged = isLogged();
  const theme = useTheme();
  const { items } = useCart();
  const quantity = items.reduce((total, item) => total + item.quantity, 0);
  const [searchText, setSearchText] = useState(getQuery("texto") || "");

  const handleSearch = () => {
    navigate(`/busca?texto=${encodeURIComponent(searchText)}`);
  };

  const handleMyOrders = () => {
    if(userIsLogged) {
      navigate('/meus-pedidos');
    } else {
      navigate('/login?ir=meus-pedidos');
    }
  };

  const handleCart = () => {
    navigate('/carrinho');
  };

  const handleKeyDown = (event: React.KeyboardEvent<HTMLInputElement>) => {
    if (event.key === 'Enter') {
      handleSearch();
    }
  };

  const handleChangeSearch = (e: any) => {
    const latinChars = latinCharsKeyboard;
    setSearchText(e.target.value.replace(latinChars, ""));
  }

  return (
    <HideOnScroll>
      <AppBar position="sticky" sx={{ backgroundColor: 'rgba(255, 255, 255, 0.98)', height: showHeaderCategories ? 120 : 88 }}>
        <>
          <Box sx={{ display: 'flex', flex: 1, justifyContent: 'space-between', padding: '0px 16px', height: '100%', alignItems: 'center' }}>

            <Box sx={{ display: 'flex' }} width={'33.33%'}>
              <Box pt={1}>
                <img src="/logo-grande.svg" alt="My Happy SVG" onClick={() => navigate('/')} style={{ cursor: 'pointer' }} />
              </Box>
            </Box>

            <Box width={'33.33%'}>
              <TextField
                placeholder="Buscar por..."
                variant="standard"
                fullWidth
                autoFocus={true}
                value={searchText}
                onChange={handleChangeSearch}
                onKeyDown={handleKeyDown}
                InputProps={{
                  disableUnderline: true,
                  style: {
                    padding: '8px',
                    paddingLeft: '16px',
                    height: '54px',
                    borderRadius: '8px', // Ajuste o valor conforme necessário para a curvatura desejada
                    backgroundColor: '#e6e6e6', // Defina a cor de fundo desejada (cinza claro)
                  },
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton type="button" aria-label="buscar" onClick={handleSearch}>
                        <SearchIcon />
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
              />
            </Box>
            <Box sx={{ display: 'flex', gap: 1, justifyContent: 'flex-end' }} width={'33.33%'}>
              <IconButton onClick={handleMyOrders} color='primary' sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '0px 16px', gap: 1 }}>
                <Typography variant="body2">
                  Meus pedidos
                </Typography>
                <PersonOutlinedIcon sx={{ fontSize: '32px' }} />
              </IconButton>
              <IconButton color='primary' onClick={handleCart}>
                <Badge badgeContent={quantity} color='error'>
                  <ShoppingCartOutlinedIcon sx={{ fontSize: '28px' }} />
                </Badge>
              </IconButton>
            </Box>
          </Box>
        </>
        {showHeaderCategories &&
          <Box sx={{ display: 'flex', height: '40px' }}>
            <HeaderCategories />
          </Box>
        }
      </AppBar>
    </HideOnScroll>
  );
};

export default HeaderLarge;