import React, { ReactNode } from "react";
import { Box, ThemeProvider } from "@mui/material";
import theme from "../theme";
import Footer from "./Footer";
import Header from "./Header";
import "./LayoutStyles.css";
import { HeaderCategories } from "./Header/HeaderLarge";

interface LayoutProps {
    children: ReactNode;
    style?: React.CSSProperties;
    hideFooter?: boolean;
    showHeaderCategories?: boolean;
}

const Layout: React.FC<LayoutProps> = ({ children, style, hideFooter, showHeaderCategories = false }) => {
    return (
        <ThemeProvider theme={theme}>
            <Header showHeaderCategories={showHeaderCategories} />
            <main style={style}>{children}</main>
            {!hideFooter && <Footer />}
        </ThemeProvider>
    );
};

export default Layout;